// Generated by OrchestKit Claude Plugin
// Created: 2026-06-03

/**
 * Memory-driven lint — feedback_*.md → tool-invocation rule registry (#1901).
 *
 * Bridges lessons that live in CC-native user memory (`feedback_*.md`) into the
 * runtime tool-invocation linter (#1883) WITHOUT requiring a PR per lesson.
 *
 * SECURITY MODEL (this is the crux — predicates come from MEMORY FILES):
 *   1. Predicates are a restricted STRUCTURED DSL ({field, op, value}), never
 *      JS. `compilePredicate` is a pure switch — there is NO eval / new Function
 *      anywhere. A `value` of "process.exit(1)" is just a literal string compared
 *      with ===; it cannot execute.
 *   2. Field resolution is a guarded dot-path walk that refuses prototype keys
 *      (__proto__, prototype, constructor).
 *   3. Memory rules may only be severity `warn` or `info` — NEVER `block`. A
 *      memory file must not be able to halt tool execution. `block` is rejected
 *      at validation time.
 *   4. Invalid entries are rejected with a collected error (never throw) so a
 *      malformed memory file degrades to "no memory rules", never a crash.
 *
 * CONVENTION (zero-dep parse): hooks ship with zero production deps, so we do
 * NOT parse arbitrary YAML. A feedback file declares rules in a fenced JSON
 * block:
 *
 *   ```ork-lint
 *   [
 *     {"id":"agent-iso-worktree","tool_name":"Agent",
 *      "predicate":{"field":"isolation","op":"eq","value":"worktree"},
 *      "severity":"warn","message":"...","see":"#1883"}
 *   ]
 *   ```
 *
 * Read by `getMemoryRules()` and merged into the linter; the static TS registry
 * wins on `id` collision (canonical beats memory), and memory advisories are
 * tagged `[memory:<file>]` so operators know the source.
 */

import { existsSync, readdirSync, readFileSync } from 'node:fs';
import { join } from 'node:path';
import type { ToolInvocationRule, RuleSeverity } from './tool-invocation-rules.js';

/** Restricted, safe predicate DSL — the only shape a memory rule may carry. */
export type PredicateSpec =
  | { field: string; op: 'eq' | 'neq' | 'prefix' | 'contains'; value: string }
  | { field: string; op: 'in'; value: string[] }
  | { field: string; op: 'exists' | 'absent' };

const ALL_OPS = new Set(['eq', 'neq', 'prefix', 'contains', 'in', 'exists', 'absent']);
// Memory rules may NOT block — only advise. `block` is rejected (see SECURITY #3).
const MEMORY_SEVERITIES = new Set<RuleSeverity>(['warn', 'info']);
const UNSAFE_KEYS = new Set(['__proto__', 'prototype', 'constructor']);
const FENCE = 'ork-lint';
const MAX_FIELD_LEN = 120;
const MAX_MESSAGE_LEN = 240;

/** Guarded dot-path resolution — refuses prototype-pollution keys. */
function resolveField(input: Record<string, unknown>, path: string): unknown {
  let cur: unknown = input;
  for (const part of path.split('.')) {
    if (cur == null || typeof cur !== 'object') return undefined;
    if (UNSAFE_KEYS.has(part)) return undefined;
    cur = (cur as Record<string, unknown>)[part];
  }
  return cur;
}

/** Coerce a resolved value to a string for matching; objects/arrays → undefined. */
function toStr(v: unknown): string | undefined {
  if (typeof v === 'string') return v;
  if (typeof v === 'number' || typeof v === 'boolean') return String(v);
  return undefined;
}

/**
 * Compile a validated PredicateSpec into a pure predicate function.
 * NO eval / new Function — a literal `switch`. Predicates that reference a
 * missing field simply don't match (defensive, matches the static-rule contract).
 */
export function compilePredicate(spec: PredicateSpec): (input: Record<string, unknown>) => boolean {
  switch (spec.op) {
    case 'exists':
      return (i) => resolveField(i, spec.field) !== undefined;
    case 'absent':
      return (i) => resolveField(i, spec.field) === undefined;
    case 'eq':
      return (i) => toStr(resolveField(i, spec.field)) === spec.value;
    case 'neq':
      return (i) => {
        const v = toStr(resolveField(i, spec.field));
        return v !== undefined && v !== spec.value;
      };
    case 'prefix':
      return (i) => {
        const v = toStr(resolveField(i, spec.field));
        return v?.startsWith(spec.value) ?? false;
      };
    case 'contains':
      return (i) => {
        const v = toStr(resolveField(i, spec.field));
        return v?.includes(spec.value) ?? false;
      };
    case 'in':
      return (i) => {
        const v = toStr(resolveField(i, spec.field));
        return v !== undefined && spec.value.includes(v);
      };
  }
}

function validateSpec(p: unknown): { ok: true; spec: PredicateSpec } | { ok: false; err: string } {
  if (!p || typeof p !== 'object') return { ok: false, err: 'predicate must be an object' };
  const rec = p as Record<string, unknown>;
  const field = rec.field;
  const op = rec.op;
  if (typeof field !== 'string' || !field) return { ok: false, err: 'predicate.field must be a non-empty string' };
  if (field.length > MAX_FIELD_LEN) return { ok: false, err: 'predicate.field too long' };
  if (typeof op !== 'string' || !ALL_OPS.has(op)) return { ok: false, err: `predicate.op invalid: ${String(op)}` };
  if (op === 'exists' || op === 'absent') return { ok: true, spec: { field, op } as PredicateSpec };
  if (op === 'in') {
    if (!Array.isArray(rec.value) || !rec.value.every((v) => typeof v === 'string')) {
      return { ok: false, err: 'predicate.value must be string[] for op "in"' };
    }
    return { ok: true, spec: { field, op, value: rec.value as string[] } };
  }
  if (typeof rec.value !== 'string') return { ok: false, err: `predicate.value must be a string for op "${op}"` };
  return { ok: true, spec: { field, op: op as 'eq' | 'neq' | 'prefix' | 'contains', value: rec.value } };
}

const ID_RE = /^[a-z0-9]+(-[a-z0-9]+)*$/;

/** A compiled, validated memory rule (a ToolInvocationRule tagged with its source). */
function validateRule(obj: unknown, file: string): { ok: true; rule: ToolInvocationRule } | { ok: false; err: string } {
  if (!obj || typeof obj !== 'object') return { ok: false, err: 'rule must be an object' };
  const r = obj as Record<string, unknown>;
  if (typeof r.id !== 'string' || !ID_RE.test(r.id)) return { ok: false, err: `rule.id must be kebab-case (got ${JSON.stringify(r.id)})` };
  if (typeof r.tool_name !== 'string' || !r.tool_name) return { ok: false, err: `rule.tool_name required (id ${r.id})` };
  if (typeof r.message !== 'string' || !r.message) return { ok: false, err: `rule.message required (id ${r.id})` };
  if (r.message.length > MAX_MESSAGE_LEN) return { ok: false, err: `rule.message too long (id ${r.id})` };
  if (typeof r.see !== 'string' || !r.see) return { ok: false, err: `rule.see required (id ${r.id})` };
  if (r.severity !== undefined && !MEMORY_SEVERITIES.has(r.severity as RuleSeverity)) {
    return { ok: false, err: `rule.severity must be warn|info — memory rules may not block (id ${r.id})` };
  }
  const sv = validateSpec(r.predicate);
  if (!sv.ok) return { ok: false, err: `${sv.err} (id ${r.id})` };
  return {
    ok: true,
    rule: {
      id: r.id,
      tool_name: r.tool_name,
      predicate: compilePredicate(sv.spec),
      severity: (r.severity as RuleSeverity) ?? 'warn',
      message: r.message,
      see: r.see,
      source: `memory:${file}`,
    },
  };
}

export interface MemoryLoadResult {
  rules: ToolInvocationRule[];
  errors: string[];
}

/** Extract the JSON body of the first ```ork-lint fenced block, or null if absent/unterminated. */
export function extractLintBlock(text: string): string | null {
  const open = text.indexOf(`\`\`\`${FENCE}`);
  if (open === -1) return null;
  const nl = text.indexOf('\n', open);
  if (nl === -1) return null;
  const close = text.indexOf('```', nl + 1);
  if (close === -1) return null;
  return text.slice(nl + 1, close).trim();
}

/** Load + validate + compile all memory lint rules under a directory. Never throws. */
export function loadMemoryRulesFromDir(dir: string): MemoryLoadResult {
  const rules: ToolInvocationRule[] = [];
  const errors: string[] = [];
  if (!dir || !existsSync(dir)) return { rules, errors };
  let files: string[];
  try {
    files = readdirSync(dir).filter((f) => f.startsWith('feedback_') && f.endsWith('.md'));
  } catch {
    return { rules, errors };
  }
  for (const f of files) {
    let text: string;
    try {
      text = readFileSync(join(dir, f), 'utf8');
    } catch {
      continue;
    }
    if (!text.includes(`\`\`\`${FENCE}`)) continue; // fast skip — most files have no block
    const body = extractLintBlock(text);
    if (body === null) {
      errors.push(`${f}: unterminated ${FENCE} block`);
      continue;
    }
    let arr: unknown;
    try {
      arr = JSON.parse(body);
    } catch {
      errors.push(`${f}: invalid JSON in ${FENCE} block`);
      continue;
    }
    if (!Array.isArray(arr)) {
      errors.push(`${f}: ${FENCE} block must be a JSON array`);
      continue;
    }
    for (const obj of arr) {
      const v = validateRule(obj, f);
      if (v.ok) rules.push(v.rule);
      else errors.push(`${f}: ${v.err}`);
    }
  }
  return { rules, errors };
}

/** Resolve the CC-native memory dir: ~/.claude/projects/<cwd-slug>/memory. */
export function resolveMemoryDir(cwd?: string): string | null {
  const override = process.env.ORK_MEMORY_DIR;
  if (override) return override;
  const home = process.env.HOME || process.env.USERPROFILE;
  const base = cwd || process.env.CLAUDE_PROJECT_DIR || '';
  if (!home || !base) return null;
  const slug = base.replace(/\//g, '-');
  return join(home, '.claude', 'projects', slug, 'memory');
}

let _cache: ToolInvocationRule[] | null = null;

/** Per-process memoized memory rules. Opt out with ORK_NO_MEMORY_LINT=1. */
export function getMemoryRules(cwd?: string): ToolInvocationRule[] {
  if (process.env.ORK_NO_MEMORY_LINT === '1') return [];
  if (_cache !== null) return _cache;
  const dir = resolveMemoryDir(cwd);
  const { rules, errors } = dir ? loadMemoryRulesFromDir(dir) : { rules: [], errors: [] };
  if (errors.length > 0) {
    try {
      process.stderr.write(`[memory-lint] skipped ${errors.length} invalid rule(s): ${errors.join('; ')}\n`);
    } catch {
      /* stderr unavailable — ignore */
    }
  }
  _cache = rules;
  return rules;
}

/** Test seam — reset the per-process cache. */
export function _resetMemoryRuleCache(): void {
  _cache = null;
}
